#include<bits/stdc++.h>
using namespace std;
int a, b, d, c, n;
double x, y;
int main() {
	cin >> n >> a >> b;
	x = 1.0 * b / a;
	for (int i = 1; i < n; i++) {
		cin >> c >> d;
		y = 1.0 * d / c;
		if (y - x >= 0.05) {
			cout << "better"<<endl;
		} else if (x - y >= 0.05) {
			cout << "worse"<<endl;
		} else {
			cout << "same"<<endl;
		}
	}
}
